class Solution:
    def mostFrequentEven(self, nums):
        evens = [x for x in nums if x % 2 == 0]
        if not evens:
            return -1
        best = None
        best_cnt = -1
        for v in sorted(set(evens)):
            c = evens.count(v)
            if c > best_cnt:
                best_cnt = c
                best = v
        return best

solutions.python:
class Solution:
    def mostFrequentEven(self, nums):
        from collections import Counter
        cnt = Counter(x for x in nums if x % 2 == 0)
        if not cnt:
            return -1
        best = -1
        best_cnt = 0
        for v, c in cnt.items():
            if c > best_cnt or (c == best_cnt and v < best):
                best = v
                best_cnt = c
        return best

