var mostFrequentEven = function(nums) {
    const cnt = new Map();
    for (const x of nums) {
        if (x % 2 === 0) cnt.set(x, (cnt.get(x) || 0) + 1);
    }
    if (cnt.size === 0) return -1;
    let best = -1, bestCnt = 0;
    for (const [v, c] of cnt) {
        if (c > bestCnt || (c === bestCnt && v < best)) {
            best = v;
            bestCnt = c;
        }
    }
    return best;
};
